import React from 'react';

const About: React.FC = () => {
    return (
        <section className="about">
            <h2>About Me</h2>
            <p>
                Welcome to my portfolio! I am a passionate developer with experience in building web applications using modern technologies. 
                My goal is to create user-friendly and efficient solutions that meet the needs of clients and users alike.
            </p>
        </section>
    );
};

export default About;
